import strawberry
from typing import List, Optional
from strawberry.types import Info
from sqlalchemy import create_engine, Column, Integer, String, ForeignKey
from sqlalchemy.orm import relationship, sessionmaker, declarative_base

Base = declarative_base()

# SQLAlchemy Models
class Product(Base):
    __tablename__ = 'products'
    id = Column(Integer, primary_key=True)
    name = Column(String)
    description = Column(String)
    price = Column(Integer)
    seller_id = Column(Integer, ForeignKey('sellers.id'))
    category_id = Column(Integer, ForeignKey('categories.id'))
    reviews = relationship('Review', back_populates='product')
    images = relationship('Image', back_populates='product')

class Review(Base):
    __tablename__ = 'reviews'
    id = Column(Integer, primary_key=True)
    content = Column(String)
    rating = Column(Integer)
    product_id = Column(Integer, ForeignKey('products.id'))
    product = relationship('Product', back_populates='reviews')

class Seller(Base):
    __tablename__ = 'sellers'
    id = Column(Integer, primary_key=True)
    name = Column(String)
    products = relationship('Product', back_populates='seller')

class Category(Base):
    __tablename__ = 'categories'
    id = Column(Integer, primary_key=True)
    name = Column(String)
    products = relationship('Product', back_populates='category')

class Image(Base):
    __tablename__ = 'images'
    id = Column(Integer, primary_key=True)
    url = Column(String)
    product_id = Column(Integer, ForeignKey('products.id'))
    product = relationship('Product', back_populates='images')

# Database setup
engine = create_engine('sqlite:///:memory:')
Base.metadata.create_all(engine)
Session = sessionmaker(bind=engine)

# Strawberry GraphQL Types
@strawberry.type
class ReviewType:
    id: int
    content: str
    rating: int

@strawberry.type
class SellerType:
    id: int
    name: str

@strawberry.type
class CategoryType:
    id: int
    name: str

@strawberry.type
class ImageType:
    id: int
    url: str

@strawberry.type
class ProductType:
    id: int
    name: str
    description: str
    price: int
    seller: SellerType
    category: CategoryType
    reviews: List[ReviewType]
    images: List[ImageType]

@strawberry.type
class Query:
    @strawberry.field
    def products(self, info: Info) -> List[ProductType]:
        db_session = Session()
        products = db_session.query(Product).all()
        return [ProductType(
            id=product.id,
            name=product.name,
            description=product.description,
            price=product.price,
            seller=SellerType(id=product.seller.id, name=product.seller.name),
            category=CategoryType(id=product.category.id, name=product.category.name),
            reviews=[
                ReviewType(id=review.id, content=review.content, rating=review.rating) for review in product.reviews
            ],
            images=[
                ImageType(id=image.id, url=image.url) for image in product.images
            ]
        ) for product in products]

schema = strawberry.Schema(query=Query)